<?php

use admin\logic\Shipping\ShippingDisplay;
use admin\logic\Shipping\ShippingPrice;
use common\logic\Eshop\Eshop;
use common\logic\Front\Cart;
use Common_Model_Eshop as ModelEshop;
use Admin_Model_ProductMeta as ProductMeta;

/**
 * Admin_Model_Shipping
 *
 * This class has been auto-generated by the Doctrine ORM Framework
 *
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
